import type { MutableRefObject } from 'react';

import type {
  DragEndProps,
  DragMoveProps,
  DragStartProps,
  PointerEventModifiers,
  RelativeAbsolutePosition,
} from '../../../../types/pointer-events.js';
import { SELECTION_RIGHT_OVERFLOW } from '../../constants.js';
import type { InteractionTriggers } from '../../types.js';
import { capSelectionAtBoundaries } from '../../utils/cap-selection-at-boundaries.js';
import { centerPositionVertically } from '../../utils/center-position-vertically.js';
import { normalizeSelectionArea } from '../../utils/normalize-selection-area.js';

export const exploreDragStart = ({
  event,
  onSelectStart,
}: {
  event: DragStartProps & PointerEventModifiers;
  onSelectStart?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
  }) => void;
}) => {
  onSelectStart?.({
    triggeredBy: 'pointer',
    position: event.startHoldingAt,
  });
};

export const exploreDragMove = ({
  event,
  height,
  width,
  onSelectChange,
}: {
  event: DragMoveProps & PointerEventModifiers;
  height: number;
  width: number;
  onSelectChange?: (event: {
    triggeredBy: InteractionTriggers;
    start: RelativeAbsolutePosition;
    end: RelativeAbsolutePosition;
    mode: 'zoom' | 'explore';
  }) => void;
}) => {
  const {
    startHoldingAt: startHoldingAtProp,
    currentPosition: currentPositionProp,
  } = event;

  const startHoldingAt = centerPositionVertically(startHoldingAtProp, height);
  const currentPosition = centerPositionVertically(currentPositionProp, height);

  const [start, end] = normalizeSelectionArea([
    startHoldingAt,
    currentPosition,
  ]);

  onSelectChange?.({
    triggeredBy: 'pointer',
    start,
    end,
    mode: 'explore',
  });
};

export const exploreDragEnd = ({
  event,
  height,
  width,
  onSelectEnd,
  lastMousePositionRef,
}: {
  event: DragEndProps & PointerEventModifiers;
  height: number;
  width: number;
  onSelectEnd?: (
    event:
      | {
          triggeredBy: InteractionTriggers;
          start: RelativeAbsolutePosition;
          end: RelativeAbsolutePosition;
        }
      | { cancelled: true },
  ) => void;
  lastMousePositionRef: MutableRefObject<RelativeAbsolutePosition | undefined>;
}) => {
  const { startHoldingAt: startHoldingAtProp, releasedAt: releasedAtProp } =
    event;

  const startHoldingAt = centerPositionVertically(startHoldingAtProp, height);
  const releasedAt = centerPositionVertically(releasedAtProp, height);

  const normalizedSelectionArea = normalizeSelectionArea([
    startHoldingAt,
    releasedAt,
  ]);

  const { start, end } = capSelectionAtBoundaries(
    normalizedSelectionArea,
    width + SELECTION_RIGHT_OVERFLOW,
  );

  if (
    start.relative.x < 0 ||
    end.relative.x > width + SELECTION_RIGHT_OVERFLOW
  ) {
    return;
  }

  onSelectEnd?.({
    triggeredBy: 'pointer',
    start,
    end,
  });
  lastMousePositionRef.current = releasedAt;
};
